  console.log('Server running on port 3000');
});

server.on('error', (err) => {
  console.error('Failed to start server:', err.message);
  process.exit(1);
});
```

---

### 8. 🌍 Hardcoded Port
Use an environment variable instead of a magic number:

```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, ...);
```

